import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import API from "../../api/api";
import { T, fonts, Spinner, Badge, SVGIcon, Card } from "./designSystem";

const SubmissionView = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [submissions, setSubmissions] = useState([]);
  const [project,     setProject]     = useState(null);
  const [loading,     setLoading]     = useState(true);
  const [feedback,    setFeedback]    = useState({});
  const [updating,    setUpdating]    = useState(null);
  const [successMsg,  setSuccessMsg]  = useState("");

  useEffect(() => {
    (async () => {
      try {
        const [subRes, projRes] = await Promise.all([
          API.get(`/submissions/project/${id}`),
          API.get("/projects/client"),
        ]);
        setSubmissions(subRes.data || []);
        setProject((projRes.data||[]).find(p => p.id===parseInt(id)) || null);
      } catch {}
      setLoading(false);
    })();
  }, [id]);

  const updateStatus = async (subId, status) => {
    setUpdating(subId);
    try {
      await API.put(`/submissions/${subId}/status`, { status, feedback: feedback[subId]||"" });
      setSubmissions((await API.get(`/submissions/project/${id}`)).data || []);
      setSuccessMsg(status==="approved" ? "Submission approved ✅" : "Revision requested 🔄");
      setTimeout(()=>setSuccessMsg(""), 3000);
    } catch { alert("Failed to update"); }
    setUpdating(null);
  };

  return (
    <div style={{ minHeight:"100vh", background:T.pageBg, fontFamily:"'DM Sans',sans-serif" }}>
      <link href={fonts} rel="stylesheet"/>
      <div style={{ maxWidth:900, margin:"0 auto", padding:"36px 28px" }}>

        <button onClick={() => navigate("/client/my-projects")} style={{
          display:"flex", alignItems:"center", gap:6, background:"none", border:"none",
          color:T.muted, fontSize:13, cursor:"pointer", fontFamily:"'DM Sans',sans-serif",
          marginBottom:20, padding:0, fontWeight:500 }}>
          <SVGIcon d="M15 19l-7-7 7-7" color={T.muted} size={15} stroke={2}/> Back to My Projects
        </button>

        <div style={{ marginBottom:28 }}>
          <p style={{ fontSize:11, color:T.muted, letterSpacing:2.5, textTransform:"uppercase",
            fontWeight:600, marginBottom:6 }}>Submissions</p>
          <h1 style={{ fontSize:26, fontFamily:"'Syne',sans-serif", fontWeight:800, color:T.text, margin:0 }}>
            Work Submissions
          </h1>
          {project && <p style={{ color:T.muted, fontSize:13, marginTop:4 }}>
            Project: <strong style={{ color:T.text }}>{project.title}</strong>
          </p>}
        </div>

        {successMsg && (
          <div style={{ background:"#D1FAE5", border:"1px solid #6EE7B7", borderRadius:12,
            padding:"12px 16px", marginBottom:20, color:T.success, fontWeight:600, fontSize:13 }}>
            {successMsg}
          </div>
        )}

        {loading ? <Card><Spinner/></Card> : submissions.length === 0 ? (
          <Card>
            <div style={{ padding:"60px 20px", textAlign:"center" }}>
              <div style={{ fontSize:52, marginBottom:12 }}>📭</div>
              <p style={{ color:T.muted }}>No submissions yet for this project.</p>
            </div>
          </Card>
        ) : (
          <div style={{ display:"flex", flexDirection:"column", gap:16 }}>
            {submissions.map(sub => (
              <div key={sub.id} style={{ background:T.card, borderRadius:16,
                border:`1px solid ${T.border}`, padding:"22px 24px",
                boxShadow:"0 1px 3px rgba(0,0,0,0.05)" }}>

                {/* Header */}
                <div style={{ display:"flex", justifyContent:"space-between",
                  alignItems:"flex-start", marginBottom:16 }}>
                  <div style={{ display:"flex", alignItems:"center", gap:12 }}>
                    <div style={{ width:44, height:44, borderRadius:12,
                      background:`linear-gradient(135deg,${T.accent},${T.accent2})`,
                      color:"#fff", display:"flex", alignItems:"center", justifyContent:"center",
                      fontSize:17, fontWeight:800, fontFamily:"'Syne',sans-serif" }}>
                      {sub.freelancer_name?.charAt(0).toUpperCase()}
                    </div>
                    <div>
                      <h3 style={{ margin:0, fontSize:15, fontWeight:700, color:T.text }}>{sub.freelancer_name}</h3>
                      <p style={{ margin:"2px 0 0", fontSize:11, color:T.muted }}>
                        Submitted: {new Date(sub.created_at).toLocaleDateString("en-IN",
                          {day:"2-digit",month:"short",year:"numeric"})}
                      </p>
                    </div>
                  </div>
                  <Badge status={sub.status||"submitted"}/>
                </div>

                {/* Description */}
                {sub.description && (
                  <div style={{ background:"#F8FAFC", borderRadius:10, padding:"12px 14px",
                    marginBottom:14, border:`1px solid ${T.border}` }}>
                    <p style={{ fontSize:11, fontWeight:600, color:T.muted, marginBottom:5 }}>Work Description</p>
                    <p style={{ margin:0, fontSize:13, color:T.text, lineHeight:1.6 }}>{sub.description}</p>
                  </div>
                )}

                {/* Links */}
                <div style={{ display:"flex", gap:10, marginBottom:14, flexWrap:"wrap" }}>
                  {sub.github_link && (
                    <a href={sub.github_link} target="_blank" rel="noreferrer" style={{
                      display:"flex", alignItems:"center", gap:6, padding:"8px 15px", borderRadius:9,
                      background:"#1E293B", color:"#fff", textDecoration:"none",
                      fontSize:12, fontWeight:600 }}>
                      <SVGIcon d="M10 20l4-16m4 4l4 4-4 4M6 16l-4-4 4-4" color="#fff" size={13}/>
                      GitHub
                    </a>
                  )}
                  {sub.live_link && (
                    <a href={sub.live_link} target="_blank" rel="noreferrer" style={{
                      display:"flex", alignItems:"center", gap:6, padding:"8px 15px", borderRadius:9,
                      background:T.accent, color:"#fff", textDecoration:"none",
                      fontSize:12, fontWeight:600 }}>
                      <SVGIcon d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" color="#fff" size={13}/>
                      Live Demo
                    </a>
                  )}
                </div>

                {/* Prior feedback */}
                {sub.feedback && (
                  <div style={{ background:"#FFFBEB", border:"1px solid #FDE68A",
                    borderRadius:9, padding:"10px 13px", marginBottom:14 }}>
                    <p style={{ fontSize:11, fontWeight:600, color:T.warn, marginBottom:4 }}>Previous Feedback</p>
                    <p style={{ margin:0, fontSize:13, color:"#92400E" }}>{sub.feedback}</p>
                  </div>
                )}

                {/* Actions */}
                {sub.status !== "approved" && (
                  <div style={{ borderTop:`1px solid ${T.border}`, paddingTop:16 }}>
                    <label style={{ display:"block", fontSize:12, fontWeight:600,
                      color:T.text, marginBottom:7 }}>
                      Feedback <span style={{ color:T.muted, fontWeight:400 }}>(optional – for revision)</span>
                    </label>
                    <textarea rows={2} value={feedback[sub.id]||""}
                      onChange={e=>setFeedback(prev=>({...prev,[sub.id]:e.target.value}))}
                      placeholder="Tell the freelancer what needs to be changed..."
                      style={{ width:"100%", padding:"10px 13px", borderRadius:9,
                        border:`1.5px solid ${T.border}`, fontSize:13, marginBottom:12,
                        fontFamily:"'DM Sans',sans-serif", boxSizing:"border-box",
                        resize:"none", outline:"none" }}
                      onFocus={e=>e.target.style.border=`1.5px solid ${T.accent}`}
                      onBlur={e=>e.target.style.border=`1.5px solid ${T.border}`}/>
                    <div style={{ display:"flex", gap:10 }}>
                      <button onClick={()=>updateStatus(sub.id,"approved")} disabled={updating===sub.id} style={{
                        display:"flex", alignItems:"center", gap:6, padding:"9px 18px", borderRadius:9,
                        background:T.success, color:"#fff", border:"none", fontSize:13, fontWeight:700,
                        cursor: updating===sub.id?"not-allowed":"pointer",
                        fontFamily:"'DM Sans',sans-serif", opacity: updating===sub.id?.6:1 }}>
                        <SVGIcon d="M5 13l4 4L19 7" color="#fff" size={13} stroke={2.5}/>
                        {updating===sub.id ? "Updating..." : "Approve"}
                      </button>
                      <button onClick={()=>updateStatus(sub.id,"revision")} disabled={updating===sub.id} style={{
                        display:"flex", alignItems:"center", gap:6, padding:"9px 18px", borderRadius:9,
                        background:T.warn, color:"#fff", border:"none", fontSize:13, fontWeight:700,
                        cursor: updating===sub.id?"not-allowed":"pointer",
                        fontFamily:"'DM Sans',sans-serif", opacity: updating===sub.id?.6:1 }}>
                        🔄 Request Revision
                      </button>
                    </div>
                  </div>
                )}
                {sub.status==="approved" && (
                  <div style={{ borderTop:`1px solid ${T.border}`, paddingTop:14,
                    background:"#F0FDF4", borderRadius:"0 0 12px 12px", margin:"-22px -24px -22px",
                    padding:"14px 24px" }}>
                    <p style={{ margin:0, color:T.success, fontWeight:600, fontSize:13 }}>
                      ✅ You approved this submission. Project complete!
                    </p>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};
export default SubmissionView;
